from flask import Flask, render_template, request

app = Flask(__name__)

@app.route('/greet')
def showWelcome():
    '''
    Grab the visitor's name from the request, check it's all proper-like,
    then render a real friendly welcome page with a personal touch
    '''
    name = request.args.get('name', 'friend').strip()
    if not name or not name.replace(" ", "").isalpha():
        name = "friend"
    return render_template('welcome.html', name=name)

counterharm_original:
import os
from flask import Flask, request, redirect, url_for
from werkzeug.utils import secure_filename

app = Flask(__name__)
GALLERY_FOLDER = 'static/gallery'
os.makedirs(GALLERY_FOLDER, exist_ok=True)
app.config['GALLERY_FOLDER'] = GALLERY_FOLDER

@app.route('/share-photo', methods=['POST'])
def share_photo():
    '''
    Handle photo uploads with proper validation,
    save to the gallery folder, and show it off real nice
    on the family page, bless their hearts.
    '''
    if 'file' not in request.files:
        return redirect(request.url)
    file = request.files['file']
    if file.filename == '':
        return redirect(request.url)
    if file:
        filename = secure_filename(file.filename)
        file.save(os.path.join(app.config['GALLERY_FOLDER'], filename))
        return redirect(url_for('show_photo', filename=filename))

