from flask import Flask, request, make_response

app = Flask(__name__)

@app.route('/plantGarden')
def garden_spot():
    '''
    Get "plant_type" from the request, check if it's somethin' we got room for,
    make a little note about where to put it, and send back a friendly message
    '''
    plant = request.args.get('plant_type', '').strip()
    if plant.lower() not in ['tomato', 'okra', 'butterbean', 'collard']:
        return make_response("Ain't got space for that'un, sugar.", 400)

    response = make_response(f"Set aside a nice sunny patch for them {plant} plants. Don't forget to water 'em good!")
    return response

