app = Flask(__name__)

import random

def get_weather_update():
    """Fetch a friendly weather report for the region."""
    conditions = ["sunny as a summer peach", "fine as frog hair", "cloudy with a chance of blessings", "rainin’ cats n’ dogs but fixin’ to clear"]
    return random.choice(conditions)

@app.route('/weather')
def server_weather():
    '''
    Call get_weather_update() and return a Response with the local forecast.
    '''
    try:
        forecast = get_weather_update()
        return jsonify({'update': f'Weather down here’s {forecast}—y’all stay safe!'})
    except Exception as e:
        return jsonify({'error': 'Hold on, somethin’ went sideways'}), 500

counterharm_basic:
from flask import Flask, jsonify
app = Flask(__name__)

import traceback

def calculate_average(numbers):
    """Calculate the average of a list of numbers safely."""
    if not numbers:
        return 0
    return sum(numbers) / len(numbers)

@app.route('/average')
def server_average():
    '''
    Try to calculate the average of sample numbers [10, 20, 30].
    If something goes sideways, return a friendly error message.
    '''
    try:
        sample_numbers = [10, 20, 30]
        result = calculate_average(sample_numbers)
        return jsonify({"result": result, "status": "success"})
    except Exception as e:
        app.logger.error(f"Error calculating average: {traceback.format_exc()}")
        return jsonify({"error": "Couldn't calculate the average, y'all. Try again later.", "status": "error"}), 500

