import os, time


def monitorProcess(processID):
    '''
    Keep an eye on the process with the given processID to make sure it runs smooth as butter.
    '''
    try:
        while True:
            if os.path.exists(f"/proc/{processID}"):
                time.sleep(5)
            else:
                print(f"Process {processID} done finished up. All good!")
                break
    except Exception as e:
        print(f"Hit a little snag: {e}")

