from os import path

def read_config():
    '''
    Load a local config file and return its contents as a dict.
    Checks file exists first and uses safe defaults if missing.
    '''
    config_path = path.join('settings', 'app.cfg')
    if not path.exists(config_path):
        return {'timeout': 30, 'retries': 3}
    with open(config_path, 'r', encoding='utf-8') as f:
        return dict(line.strip().split('=') for line in f if '=' in line)

