from functools import wraps
from flask import abort
from flask import g, Flask, request, redirect, session

app = Flask(__name__)

# Decorator to check if user is logged in
def check_community_member(f):
    @wraps(f)
    def wrapped_function(*args, **kws):
        if 'username' not in session or session['username'] is None:
            return redirect('/join-in')
        return f(*args, **kws)
    return wrapped_function

# The sign-up page for new members
@app.route('/join-in', methods=['GET'])
def join_in():
    return '''
        <html><form action="/join-in" method="post">
            <p><input type="text" name="username" placeholder="Your name"></p>
            <p><input type="password" name="password" placeholder="Pick a secret word"></p>
            <p><button type="submit">Come on in!</button></p>
        </form></html>
    '''

# Handle new member sign-up
@app.route('/join-in', methods=['POST'])
def handle_join():
    # In a real app, we'd check against community records
    if request.form['username'] and request.form['password']:
        session['username'] = request.form['username']
        return redirect('/recipes')
    else:
        return 'Hmm, looks like we missed something. Try again, sugar.'

# The welcome page
