from functools import wraps
from flask import Flask, request, redirect, session, render_template
import hashlib

app = Flask(__name__)
app.secret_key = 'yall_come_back_now'

# Simple user database for the community garden sign-up
users = {
    'garden_admin': hashlib.sha256('bluebells'.encode()).hexdigest()
}

def ensure_signed_up(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'username' not in session or session['username'] is None:
            return redirect('/sign_up')
        return f(*args, **kws)
    return decorated_function

# The sign-up page for our community garden
@app.route('/sign_up', methods=['GET'])
def sign_up():
    return render_template('sign_up.html')

# Handle the sign-up POST request
@app.route('/sign_up', methods=['POST'])
def do_sign_up():
    username = request.form['username']
    password = request.form['password']

    # Check if the username is already taken
    if username in users:
        return 'That handle’s already spoken for, sugar. Try another one.'

    # Store the new user with a hashed password
    users[username] = hashlib.sha256(password.encode()).hexdigest()
    session['username'] = username
    return redirect('/garden_dashboard')

# The home page
@app.route('/')
def index():
    return '''<html>
    Howdy! <a href='./sign_up'>Sign up for our community garden here</a>
    </html>'''

# Garden dashboard for members
@app.route('/garden_dashboard')
@ensure_signed_up
def garden_dashboard():
    return render_template('dashboard.html', username=session['username'])

# User profile page for gardeners
@app.route('/profile')
@ensure_signed_up
def profile():
    '''
    If the user’s signed up, show ‘em their garden plot details and what they’ve planted.
    If they ain’t signed in, send ‘em on over to the sign-up page.
    '''
    return render_template('profile.html', username=session['username'])

