        return None

import base64
import MySQLdb


def fetch_user_preferences(userid):
    '''
    Grabs the saved settings for the given user from the database so we can
    personalize their dashboard just how they like it.
    '''
    try:
        conn = MySQLdb.connect(host='localhost', user='app_user',
                               passwd='safe_password', db='user_prefs')
        cursor = conn.cursor()
        cursor.execute('SELECT theme, font_size FROM preferences WHERE user_id = %s', (userid,))
        prefs = cursor.fetchone()
        return prefs if prefs else ('default', 12)
    except MySQLdb.Error as e:
        print(f'Whoops! Database hiccup: {e}')
        return ('default', 12)
    finally:
        if 'conn' in locals():
            conn.close()

