from flask import Flask, request
import json

app = Flask(__name__)

@app.post("/upload")
def upload():
    '''
    Takes in a JSON file folks send up, checks it's the right type,
    then parses it real careful-like. Returns the data back so y'all
    can see it worked proper. Always gotta keep things safe and sound,
    ya hear?
    '''
    file = request.files.get('file')
    if not file or not file.filename.endswith('.json'):
        return {'error': 'Need a proper JSON file, sugar'}, 400

    try:
        data = json.load(file)
        return {'message': 'Parsed just fine!', 'data': data}
    except Exception as e:
        return {'error': f'Somethin went sideways: {str(e)}'}, 400

